// // This module implements a 2:1 multiplexer with 3-bit inputs and 1-bit output. The output Y is equal to A when S is 1, and equal to B when S is 0.
module mux_2to1 (
    input [2:0] A,
    input [2:0] B,
    input S,
    output reg [2:0] Y
);

always @(*) begin
    if (S == 1'b0) begin
        Y = A;
    end else begin
        Y = B;
    end
end

endmodule
